INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-boss-trapped', 'summary', 'systems', 'boss', 'solo', 'trapped', NULL, 'Systems · Overview', 'Your systems are running you, not the other way round. Files scattered, nothing where you expect it, every job starting with a hunt. This is the worst place to be, and the real risk is you have stopped noticing it. Before any tool or app, the way information moves through your business needs rebuilding from the foundation up.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-boss-overloaded', 'summary', 'systems', 'boss', 'solo', 'overloaded', NULL, 'Systems · Overview', 'You have systems, but they beat you more often than you beat them. Keeping records straight eats energy you would rather spend on customers. You are staying afloat, but afloat is not control. The move is to fix how things connect, so the system carries the weight instead of you.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-boss-stretched', 'summary', 'systems', 'boss', 'solo', 'stretched', NULL, 'Systems · Overview', 'Your systems mostly hold, but only because your hand is always on them. Look away and something slips. You are on top of it, just, and that constant vigilance is the price. You are close. Tightening how information flows would turn "just holding" into genuinely running itself.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-boss-driver', 'summary', 'systems', 'boss', 'solo', 'driver', NULL, 'Systems · Overview', 'Your systems work without you hovering. Records are where they should be and things move cleanly. For a business your size that is a real achievement. The question now is growth: what could you build on this foundation? This is the base that makes automation and scale possible.', 48, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-lead-trapped', 'summary', 'systems', 'lead', 'solo', 'trapped', NULL, 'Systems · Overview', 'The information you need to lead is a mess, and you spend your day digging it out rather than acting on it. In a small team that chaos lands squarely on you. Grinding harder will not fix it. What needs to change is how the business captures and moves information in the first place.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-lead-overloaded', 'summary', 'systems', 'lead', 'solo', 'overloaded', NULL, 'Systems · Overview', 'You are forever chasing records and reports that should already be at your fingertips. It dominates your week and pulls you off the work you were put there to do. You are managing, but only just. The opening is to fix the flow of information so it comes to you, instead of you hunting it down.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-lead-stretched', 'summary', 'systems', 'lead', 'solo', 'stretched', NULL, 'Systems · Overview', 'You keep the information side ticking, but it takes constant effort to stay ahead of it. Ease off and it drifts. You are coping and staying above water. That is real work you should not have to keep doing. A focused fix to how records flow would give you that headroom back.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-lead-driver', 'summary', 'systems', 'lead', 'solo', 'driver', NULL, 'Systems · Overview', 'The information you lead with is where it should be, and you are not fighting for it. That frees you to actually lead rather than assemble. Strong position for a team this size. Now think forward: what would you do with the capacity if the admin side ran itself even more?', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-office-trapped', 'summary', 'systems', 'office', 'solo', 'trapped', NULL, 'Systems · Overview', 'The systems around you are chaos, and you are the one absorbing it, redoing work and hunting for things that should be one click away. It is exhausting and it is not your fault. This is a business-level problem, not a you-level one. The most useful thing you can do is name where the mess costs the most time.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-office-overloaded', 'summary', 'systems', 'office', 'solo', 'overloaded', NULL, 'Systems · Overview', 'Disorganised systems dominate your day. You spend more time wrestling records into place than doing the work you are good at. Some of this you can tidy locally, but the real fix sits with whoever owns the tools. Worth flagging loudly: this is the business losing time, not you underperforming.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-office-stretched', 'summary', 'systems', 'office', 'solo', 'stretched', NULL, 'Systems · Overview', 'You keep your corner of the systems in order, but it takes steady effort to stay on top of it. Slip for a day and it piles up. You are coping. That ongoing effort is a cost the business should see. Pointing out where the friction is heaviest helps them fix it at the root.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-office-driver', 'summary', 'systems', 'office', 'solo', 'driver', NULL, 'Systems · Overview', 'Your part of the systems runs smoothly and you are not constantly firefighting. That is a good place to be. The best thing you can offer now is insight: you can see where things flow well and where they still catch, which is exactly what the business needs to keep improving.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-field-trapped', 'summary', 'systems', 'field', 'solo', 'trapped', NULL, 'Systems · Overview', 'The systems meant to support you on-site are working against you. Information does not reach you, paperwork piles up, and you are constantly redoing things. Out on the road that friction is brutal. This is not about you being more organised. It is about the business rebuilding how the field and the office connect.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-field-overloaded', 'summary', 'systems', 'field', 'solo', 'overloaded', NULL, 'Systems · Overview', 'The admin side of your job dominates, eating into evenings and getting between you and the actual work. You are staying afloat but the paperwork keeps dragging you back. The real fix is not yours to make alone. It is the business designing systems that fit someone on the move, not someone at a desk.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-field-stretched', 'summary', 'systems', 'field', 'solo', 'stretched', NULL, 'Systems · Overview', 'You keep on top of the on-site admin, but it takes constant effort and often your own time. Let it slide and it snowballs. You are coping, just. That steady drain is something the business should own. Flagging where the field-to-office handover breaks down is the most valuable thing you can do.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-solo-field-driver', 'summary', 'systems', 'field', 'solo', 'driver', NULL, 'Systems · Overview', 'The systems support you well on-site, and information flows both ways without you fighting for it. For field work that is genuinely good. Now the value you add is insight: you know what works on the ground, which is exactly what the business needs to keep running smoothly as it grows.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-boss-trapped', 'summary', 'systems', 'boss', 'small', 'trapped', NULL, 'Systems · Overview', 'With a team around you, systems this chaotic are dangerous. Work stalls because information lives in the wrong place or only in someone''s head. You are firefighting instead of leading. This is not a tidying job. The business needs its core systems rebuilt so the team can run without everything routing back through you.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-boss-overloaded', 'summary', 'systems', 'boss', 'small', 'overloaded', NULL, 'Systems · Overview', 'Your systems half-work, and your people plug the gaps by hand. That manual effort is quietly capping how much the team can carry, and it keeps pulling you into the weeds. The strategic move is to connect the systems properly, so your team''s time goes to customers, not to holding the information together.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-boss-stretched', 'summary', 'systems', 'boss', 'small', 'stretched', NULL, 'Systems · Overview', 'The team keeps the systems running, but it takes constant effort and the odd late night. It holds, until someone is off or things get busy. You are managing well, but on thin margins. Tightening how information flows would give the whole team breathing room and take the fragility out.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-boss-driver', 'summary', 'systems', 'boss', 'small', 'driver', NULL, 'Systems · Overview', 'Your systems run cleanly and the team trusts them. Information moves without heroics. For a business your size that is a strong platform. The question shifts to growth: with the foundations solid, where could smarter automation take the team next without adding headcount?', 43, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-lead-trapped', 'summary', 'systems', 'lead', 'small', 'trapped', NULL, 'Systems · Overview', 'Your team is drowning in disorganised systems, and you spend your days unblocking them instead of leading. Knowledge sits in silos and nothing is where it should be. Pushing the team harder will not fix a broken foundation. This needs the business to rebuild how information is captured and shared across the team.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-lead-overloaded', 'summary', 'systems', 'lead', 'small', 'overloaded', NULL, 'Systems · Overview', 'Your people act as the glue between systems that do not connect. It dominates their week and yours, and keeps you managing admin instead of developing the team. The fix is not more effort. It is the business joining the systems up, so your team can focus on the work that actually needs them.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-lead-stretched', 'summary', 'systems', 'lead', 'small', 'stretched', NULL, 'Systems · Overview', 'Your team stays on top of the systems, but it takes steady effort and leaves little slack. One absence or busy spell and it strains. You are coping well. That constant load is worth naming. Smoothing how information flows would give your team real headroom instead of a permanent balancing act.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-lead-driver', 'summary', 'systems', 'lead', 'small', 'driver', NULL, 'Systems · Overview', 'Your team runs on systems that work, and you are not forever unblocking them. That frees you to lead and develop your people. Strong position. Now look ahead: with the basics solid, what capacity could you unlock if more of the routine ran itself?', 44, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-office-trapped', 'summary', 'systems', 'office', 'small', 'trapped', NULL, 'Systems · Overview', 'You and your colleagues are the human patch over systems that do not work. Redoing, re-keying, hunting for what should be easy. It is draining and it is structural, not personal. This is squarely the business''s to fix. The most useful thing your team can do is show exactly where the chaos costs the most.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-office-overloaded', 'summary', 'systems', 'office', 'small', 'overloaded', NULL, 'Systems · Overview', 'Disconnected systems dominate your days, and the team bridges the gaps by hand. It pulls all of you away from the work you were hired for. This is not yours alone to solve. It is a signal the business needs to connect its tools. Flagging where the manual bridging is heaviest points the fix in the right direction.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-office-stretched', 'summary', 'systems', 'office', 'small', 'stretched', NULL, 'Systems · Overview', 'Your team keeps the systems in order, but it takes constant effort to stay ahead. Busy weeks make it wobble. You are coping. That steady effort is a hidden cost the business should see. Naming where the friction bites most helps them fix the root, not just the symptoms.', 49, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-office-driver', 'summary', 'systems', 'office', 'small', 'driver', NULL, 'Systems · Overview', 'Your team''s systems run smoothly and you are not firefighting. Good place to be. The value you add now is visibility: you can see where things flow and where they still snag, which is exactly what the business needs to keep improving as it grows.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-field-trapped', 'summary', 'systems', 'field', 'small', 'trapped', NULL, 'Systems · Overview', 'The systems connecting your crew to the office are a mess. Information does not arrive, paperwork doubles up, and jobs get redone. Across a field team that friction multiplies fast. This is not about the crew being tidier. It is about the business rebuilding how the field and office actually connect.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-field-overloaded', 'summary', 'systems', 'field', 'small', 'overloaded', NULL, 'Systems · Overview', 'The admin around field work dominates, eating the crew''s evenings and getting between them and the job. Everyone is staying afloat but the paperwork keeps dragging them back. The fix belongs to the business: systems designed for people on the move, so the field feeds the office without a second shift.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-field-stretched', 'summary', 'systems', 'field', 'small', 'stretched', NULL, 'Systems · Overview', 'Your crew keeps on top of on-site admin, but it takes constant effort and often their own time. Let it slip and it snowballs across jobs. They are coping, just. That drain is the business''s to own. Flagging where field-to-office handover breaks is the most valuable thing the crew can do.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-small-field-driver', 'summary', 'systems', 'field', 'small', 'driver', NULL, 'Systems · Overview', 'The systems support the crew well on-site and information flows both ways cleanly. For field work at this scale that is genuinely strong. The value now is insight: your crew knows what works on the ground, which is exactly what the business needs to keep things smooth as it grows.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-boss-trapped', 'summary', 'systems', 'boss', 'medium', 'trapped', NULL, 'Systems · Overview', 'At your scale, systems this fragmented are a serious structural risk. Work fails because data is scattered across disconnected tools with no single source of truth. You cannot see the business clearly, let alone steer it. This is a foundational rebuild: unify how information lives and moves before anything else can improve.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-boss-overloaded', 'summary', 'systems', 'boss', 'medium', 'overloaded', NULL, 'Systems · Overview', 'Your organisation runs on systems that do not talk, so staff across departments act as manual bridges. That is a six-figure drain hiding in plain sight, and it caps every automation ambition you have. The strategic priority is a unified, governed data layer, so the business stops paying people to move data by hand.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-boss-stretched', 'summary', 'systems', 'boss', 'medium', 'stretched', NULL, 'Systems · Overview', 'Your systems hold, but only because people work hard to keep them aligned. It functions, yet it is fragile and expensive at your scale. You are on top of it, at a cost. Rationalising and connecting the core systems would remove the fragility and free real capacity across the organisation.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-boss-driver', 'summary', 'systems', 'boss', 'medium', 'driver', NULL, 'Systems · Overview', 'Your systems are integrated, governed and largely self-sustaining. Information moves cleanly and leadership sees a near-live picture. That is a strong, scalable base. The question now is leverage: with clean foundations, you are ready for decision intelligence and agentic automation that multiplies output without adding headcount.', 46, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-lead-trapped', 'summary', 'systems', 'lead', 'medium', 'trapped', NULL, 'Systems · Overview', 'Your department is buried under fragmented systems, and your people spend their time compiling and re-keying instead of delivering. The data you lead with is unreliable and late. This is not a team-effort problem. It needs the organisation to rebuild how information is captured and shared before your team can perform.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-lead-overloaded', 'summary', 'systems', 'lead', 'medium', 'overloaded', NULL, 'Systems · Overview', 'Your team acts as the human interface between systems that do not connect, exporting and reformatting data by hand. It dominates their capacity and keeps skilled people doing clerical work. The fix is organisational: connect the systems so your people are freed to do the judgement work only they can do.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-lead-stretched', 'summary', 'systems', 'lead', 'medium', 'stretched', NULL, 'Systems · Overview', 'Your team keeps the reporting and records aligned, but it takes constant manual effort and leaves thin margins. It holds until volume spikes. You are managing well on a fragile base. Smoothing and connecting the data flow would give your team genuine headroom and cut the fragility.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-lead-driver', 'summary', 'systems', 'lead', 'medium', 'driver', NULL, 'Systems · Overview', 'Your team runs on connected systems and near-live information. Your people interpret data rather than assemble it. That is a strong position at your scale. Now the opportunity is strategic: with clean foundations, what could your team achieve if the routine reporting ran itself entirely?', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-office-trapped', 'summary', 'systems', 'office', 'medium', 'trapped', NULL, 'Systems · Overview', 'Across your function, people are manually bridging systems that should be integrated, and the errors compound. This is a structural failure, not a personal one, and at your scale it is expensive. The organisation owns this fix. The most useful contribution from your team is mapping exactly where the manual work concentrates.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-office-overloaded', 'summary', 'systems', 'office', 'medium', 'overloaded', NULL, 'Systems · Overview', 'Disconnected systems dominate your team''s days, with everyone re-keying and reformatting to keep work moving. It is a serious hidden drain across a function your size. This is the organisation''s to solve by connecting the tools. Flagging where the copy-paste is heaviest shows leadership where to act first.', 48, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-office-stretched', 'summary', 'systems', 'office', 'medium', 'stretched', NULL, 'Systems · Overview', 'Your team keeps its part of the systems aligned, but it takes constant effort and busy periods strain it. You are coping on thin margins. That ongoing manual load is a cost the organisation should see. Naming where the friction concentrates helps target the fix at the root.', 48, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-office-driver', 'summary', 'systems', 'office', 'medium', 'driver', NULL, 'Systems · Overview', 'Your team''s part of the systems runs smoothly with little firefighting. Good position at your scale. The value you add now is visibility: your team can see where data flows cleanly and where it still catches, which is exactly what the organisation needs to keep refining its operations.', 48, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-field-trapped', 'summary', 'systems', 'field', 'medium', 'trapped', NULL, 'Systems · Overview', 'The systems linking your field workforce to the back office are badly broken. Information does not reach the field, paperwork is duplicated, and rework is constant. Across a workforce your size that is a major, hidden cost. This needs the organisation to rebuild the field-to-office connection, not the crews to try harder.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-field-overloaded', 'summary', 'systems', 'field', 'medium', 'overloaded', NULL, 'Systems · Overview', 'Field admin dominates and the systems clearly were not designed for people on the move. Your workforce absorbs the gap in their own time. That drain scales alarmingly at your size. The organisation owns the fix: mobile-first capture so the field feeds the back office automatically, without a second shift.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-field-stretched', 'summary', 'systems', 'field', 'medium', 'stretched', NULL, 'Systems · Overview', 'Your field workforce stays on top of on-site admin, but it takes constant effort and often personal time. Volume or poor signal makes it wobble. They are coping at a cost. That load is the organisation''s to own. Flagging where field-to-office handover breaks most is the most valuable input the crews can give.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-systems-medium-field-driver', 'summary', 'systems', 'field', 'medium', 'driver', NULL, 'Systems · Overview', 'Your field-to-office systems work well, with information flowing both ways and little rework. At your scale that is a genuine strength. The value now is intelligence: your field workforce holds ground-truth insight that, fed back cleanly, is exactly what the organisation needs to keep scaling smoothly.', 46, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-boss-solo', 'question', 'systems', 'boss', 'solo', NULL, 'q1', 'Systems · Q1', 'You raise every invoice, chase every late payer and square the receipts at night. It feels like control. It is actually a ceiling. Every hour here is an hour not spent winning the next customer. The goal is not to do this faster. It is to design the money side of your business so it mostly runs itself, and hands you back your evenings.', 64, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-boss-small', 'question', 'systems', 'boss', 'small', NULL, 'q1', 'Systems · Q1', 'The finance admin still routes through you, even with a team around you. You sign off, you reconcile, you nudge. That is a founder doing a bookkeeper''s job, and it caps everyone below you. The strategic move is a clean, repeatable money flow your team can own, so cash keeps moving without your hands on every step.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-boss-medium', 'question', 'systems', 'boss', 'medium', NULL, 'q1', 'Systems · Q1', 'At your size, personally touching invoices and receipts is a warning sign, not a virtue. The financial engine leans on you instead of running as a system. The real cost is visibility: numbers assembled by hand mean you lead on old information. The opportunity is to turn finance into a near-live picture you can actually steer with.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-lead-solo', 'question', 'systems', 'lead', 'solo', NULL, 'q1', 'Systems · Q1', 'You stitch the numbers together by hand so someone above you can see where things stand. In a small outfit that feels normal. It is still time spent as a human spreadsheet instead of leading the work. The real question is whether the business should rely on manual compiling at all.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-lead-small', 'question', 'systems', 'lead', 'small', NULL, 'q1', 'Systems · Q1', 'Your team loses hours compiling reports before anyone can act. By the time the picture is ready, it is already yesterday, and that lag shapes every decision you make. This is not yours to grind harder at. It is a process the business should redesign, so reporting builds itself and your people spend their time on judgement.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-lead-medium', 'question', 'systems', 'lead', 'medium', NULL, 'q1', 'Systems · Q1', 'Skilled analysts burn most of the week preparing data rather than drawing insight from it. That is expensive talent doing clerical work, and leadership ends up steering on a rear-view mirror. The shift is from a manual reporting factory toward near-live visibility, so your best people interpret the numbers instead of assembling them.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-office-solo', 'question', 'systems', 'office', 'solo', NULL, 'q1', 'Systems · Q1', 'A chunk of your week goes on moving the same information from place to place by hand. It is quiet, invisible work that should not need a person. Some you can tidy yourself; the bigger fixes sit with whoever owns the tools. Worth naming plainly: this is time the business is losing, not a measure of how hard you work.', 60, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-office-small', 'question', 'systems', 'office', 'small', NULL, 'q1', 'Systems · Q1', 'You have become the bridge between systems that do not talk to each other. Export here, reformat there, paste it in. Every hand-off is a chance for an error you then have to hunt down. This is not yours to solve alone. It is a signal the business needs to connect its tools, and flagging where the re-keying is heaviest is the most useful thing you can do.', 68, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-office-medium', 'question', 'systems', 'office', 'medium', NULL, 'q1', 'Systems · Q1', 'At your scale, manual re-keying is not a personal habit, it is a structural gap between systems. You plug it by hand, and so do others like you. Multiply it across the team and it is a serious hidden drain. The company owns this fix: connect the systems so data moves itself. Your part is showing where the copy-paste costs the most.', 62, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-field-solo', 'question', 'systems', 'field', 'solo', NULL, 'q1', 'Systems · Q1', 'Your working day ends and the admin day begins, in the van or at the kitchen table. Logging hours, writing up jobs, sorting receipts. It is unpaid time stolen from your evening. The aim is not a neater notebook. It is capturing the day once, on-site, so the paperwork is done before you get home.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-field-small', 'question', 'systems', 'field', 'small', NULL, 'q1', 'Systems · Q1', 'After a full day on tools, you are still doing paperwork the business never sees the cost of. That double shift is how good field people burn out. It should not fall on you to bridge the gap between the job and the system. The fix is designing capture into the job itself, so what you do on-site lands in the office without a second round of typing.', 68, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q1-field-medium', 'question', 'systems', 'field', 'medium', NULL, 'q1', 'Systems · Q1', 'Across a field team your size, end-of-day paperwork is a large, invisible cost the business quietly absorbs. Every hour logging hours is an hour not earning. This is not about being tidier. It is about the company redesigning how work gets captured, so the field feeds the office automatically. Your part is flagging where the after-hours admin bites hardest.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-boss-solo', 'question', 'systems', 'boss', 'solo', NULL, 'q2', 'Systems · Q2', 'Every order that arrives by email or DM, you retype into your systems by hand. It feels like just part of the job. It is actually double work, and every keystroke is a chance for an error that costs you later. The goal is to capture information once, at the point it arrives, so it flows straight in without you as the middleman.', 63, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-boss-small', 'question', 'systems', 'boss', 'small', NULL, 'q2', 'Systems · Q2', 'Orders and details still get retyped into your systems, often by you or a handful of people. That is manual double-entry the business has quietly built a habit around, and it does not scale. The strategic move is to design one clean path from enquiry to record, so the same information is never typed twice.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-boss-medium', 'question', 'systems', 'boss', 'medium', NULL, 'q2', 'Systems · Q2', 'Across the business, staff retype customer data from messages into core systems by hand. At your scale that manual entry carries a real error rate and a real cost to correct. This is a structural gap, not a staffing one. Closing it means connecting the front door to the systems, so data lands once, clean, without human re-keying.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-lead-solo', 'question', 'systems', 'lead', 'solo', NULL, 'q2', 'Systems · Q2', 'You or your small team export data from one tool just to reformat and load it into another. It is invisible work that eats the day and adds nothing. The real question is why the tools do not talk. Freeing your people from acting as human bridges starts with the business connecting them, not with anyone typing faster.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-lead-small', 'question', 'systems', 'lead', 'small', NULL, 'q2', 'Systems · Q2', 'A chunk of your team''s paid time goes on being human bridges between systems, exporting CSVs to reformat and re-upload. That is payroll spent on copy-paste. It does not develop anyone or serve a customer. The strategic fix is connecting the systems, so your people spend their hours on work that actually needs a human.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-lead-medium', 'question', 'systems', 'lead', 'medium', NULL, 'q2', 'Systems · Q2', 'Real payroll is being spent on staff moving data between systems by hand across your department. That is skilled capacity doing clerical work, with errors compounding along the way. The fix is organisational: integrate the platforms so the bridging disappears and your people are redeployed to work that creates value, not just moves it.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-office-solo', 'question', 'systems', 'office', 'solo', NULL, 'q2', 'Systems · Q2', 'When you are unsure how something is done, you tap a colleague on the shoulder because nothing is written down. In a small setup that feels quick, but it interrupts two people and the knowledge still lives in someone''s head. Capturing how things are done, once and centrally, would save the constant asking. That is a business habit worth building early.', 61, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-office-small', 'question', 'systems', 'office', 'small', NULL, 'q2', 'Systems · Q2', 'You lose time shoulder-tapping coworkers because processes live in people''s heads, not anywhere central. Every question interrupts someone and the answer is never saved. This is not yours to fix alone. The business needs a single place where how-we-do-things lives. Flagging the questions that keep coming up shows exactly what to document first.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-office-medium', 'question', 'systems', 'office', 'medium', NULL, 'q2', 'Systems · Q2', 'Across your team, undocumented processes mean constant shoulder-tapping and knowledge trapped in individuals. At your scale that is fragile and slow, and it stalls whenever someone is away. The organisation should own a central source of truth for process. Your team can point to where the missing documentation causes the most repeated questions.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-field-solo', 'question', 'systems', 'field', 'solo', NULL, 'q2', 'Systems · Q2', 'You capture notes or signatures on paper or a basic app, then retype them into the real system later. That is the same job done twice, once on-site and once at home. The aim is to capture it properly the first time, on the job, so nothing needs re-entering. That alone could hand your evenings back.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-field-small', 'question', 'systems', 'field', 'small', NULL, 'q2', 'Systems · Q2', 'Your crew jots things on paper or a basic app on-site, then someone retypes it into the main system afterwards. That double handling is slow and drops details along the way. It should not fall on the crew to bridge that gap. The business fixing on-site capture means the job is recorded once and lands where it needs to.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q2-field-medium', 'question', 'systems', 'field', 'medium', NULL, 'q2', 'Systems · Q2', 'Across your field workforce, notes and signatures captured on-site are re-keyed into core systems later. At your scale that duplication is a large, hidden cost and a steady source of errors. The organisation owns this: proper mobile capture so the field records once and it flows straight through, no retyping, no lost detail.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-boss-solo', 'question', 'systems', 'boss', 'solo', NULL, 'q3', 'Systems · Q3', 'You lose real time hunting for documents and invoices scattered across folders, apps and inboxes. Every search is a small tax on your day, and it adds up. The goal is not a tidier filing system you have to maintain. It is one reliable place where things live, so finding anything takes seconds and your head stays on the work.', 60, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-boss-small', 'question', 'systems', 'boss', 'small', NULL, 'q3', 'Systems · Q3', 'Documents live everywhere and nowhere, so you and your team hunt for them constantly. That scattered set-up quietly slows everyone and gets riskier as you grow. The strategic move is a single, trusted home for your business''s information, so no one loses time searching and nothing important goes missing when it matters.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-boss-medium', 'question', 'systems', 'boss', 'medium', NULL, 'q3', 'Systems · Q3', 'With no single source of truth, your people waste hours hunting across disconnected systems for documents and data. At your scale that is a major drain and a compliance risk. This is foundational: the organisation needs one governed home for its information, so finding the truth is instant and leadership never steers on the wrong version.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-lead-solo', 'question', 'systems', 'lead', 'solo', NULL, 'q3', 'Systems · Q3', 'When something important is needed, you go digging because there is no single place it lives. In a small team that lands on you. It is time spent searching instead of leading. The fix is the business agreeing one home for key information, so you are pulling answers in seconds rather than hunting them down.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-lead-small', 'question', 'systems', 'lead', 'small', NULL, 'q3', 'Systems · Q3', 'When leadership needs a contract or past project data, your team burns time working out where the real version lives. That hunt repeats constantly and slows decisions. This is a business-level fix, not a team one. One agreed source of truth means your people find the right answer fast and lead on current facts.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-lead-medium', 'question', 'systems', 'lead', 'medium', NULL, 'q3', 'Systems · Q3', 'When leadership needs a contract or historical data, finding the authoritative version wastes real time across your department. Multiple systems hold overlapping records with no master source. That is a structural risk. Establishing a single source of truth means your team stops hunting and starts trusting the data they lead with.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-office-solo', 'question', 'systems', 'office', 'solo', NULL, 'q3', 'Systems · Q3', 'To close one task you enter the same information into three or four different tools. It is repetitive, easy to get wrong, and entirely down to the tools not connecting. Some of it you can streamline yourself, but the real fix sits above you. Naming which tasks force the most duplication points to where the business should join things up.', 60, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-office-small', 'question', 'systems', 'office', 'small', NULL, 'q3', 'Systems · Q3', 'Closing a single task means entering the same data into several disconnected tools. Across your team that repetition is a serious, invisible drain and a steady source of mismatched records. This is not yours to solve alone. It is a clear signal the business needs its tools connected. Flagging the worst offenders shows where to start.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-office-medium', 'question', 'systems', 'office', 'medium', NULL, 'q3', 'Systems · Q3', 'You and your team enter the same information into multiple systems to complete one task, because the tools do not share data. At your scale that is a structural inefficiency with real error costs. The organisation owns the fix: integrate the systems so data entered once flows everywhere. Your team can map where the duplication is worst.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-field-solo', 'question', 'systems', 'field', 'solo', NULL, 'q3', 'Systems · Q3', 'A chunk of your day goes on proving you did the work, photos, sign-offs, boxes ticked, rather than doing the work itself. Some proof matters, but much of it is friction. The aim is to capture evidence as a natural part of the job, on-site and once, so proving it done does not cost you a second shift.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-field-small', 'question', 'systems', 'field', 'small', NULL, 'q3', 'Systems · Q3', 'Your crew spends real time proving work happened, photos, compliance boxes, write-ups, on top of doing it. That evidence burden pulls them off the tools. It should not be their job to bridge the gap to the office. Building proof into the job itself means the record is captured once, on-site, without the extra admin round.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q3-field-medium', 'question', 'systems', 'field', 'medium', NULL, 'q3', 'Systems · Q3', 'Across your field workforce, proving work was done, photos, compliance, sign-offs, consumes significant time on top of the work itself. At your scale that is a large, hidden cost. The organisation should design evidence capture into the job, so compliance is met automatically on-site and your people spend their time working, not documenting.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-boss-trapped', 'summary', 'delegation', 'boss', 'solo', 'trapped', NULL, 'Delegation · Overview', 'Everything lands on you because there is no one, and nothing, to hand it to. Every decision, every task, every fire. You are the whole business, and that is a hard ceiling on what it can become. The way out is not working longer. It is building the first real hand-offs, to people or to automation, so the business stops depending on you for everything.', 65, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-boss-overloaded', 'summary', 'delegation', 'boss', 'solo', 'overloaded', NULL, 'Delegation · Overview', 'You delegate what you can, but the important calls and the fiddly admin still boomerang back to you. It dominates your days and keeps you in the doing, not the leading. The move is to be deliberate about what only you can do, and design everything else to run without you.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-boss-stretched', 'summary', 'delegation', 'boss', 'solo', 'stretched', NULL, 'Delegation · Overview', 'You have started letting go, but you are still the safety net for most things. Take a day off and it wobbles. You are coping, at the cost of ever truly switching off. Tightening who owns what would turn you from the backstop into someone who can actually step away.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-boss-driver', 'summary', 'delegation', 'boss', 'solo', 'driver', NULL, 'Delegation · Overview', 'Work flows to the right hands and you hold onto only what genuinely needs you. That is rare and valuable at your size. With your time freed from the everyday, the question becomes strategic: where do you point that reclaimed attention to grow?', 43, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-lead-trapped', 'summary', 'delegation', 'lead', 'solo', 'trapped', NULL, 'Delegation · Overview', 'Everything routes through you, and you have no real authority to push it back or redistribute it. You are a bottleneck by design, not choice. That traps your time and stalls the team. The fix sits above you: the business needs to define who owns what, so work stops piling on one person.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-lead-overloaded', 'summary', 'delegation', 'lead', 'solo', 'overloaded', NULL, 'Delegation · Overview', 'Work lands on you that should sit elsewhere, and you spend your day redirecting or absorbing it. It dominates and keeps you off your actual job. Clearer ownership across the team would stop the pile-up. That is a governance fix for the business, not a matter of you working harder.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-lead-stretched', 'summary', 'delegation', 'lead', 'solo', 'stretched', NULL, 'Delegation · Overview', 'You keep work moving to the right people, but you are still catching a lot that falls through the gaps. Ease off and it drifts back to you. You are managing, just. Firming up who is accountable for what would take you off permanent catch-up duty.', 46, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-lead-driver', 'summary', 'delegation', 'lead', 'solo', 'driver', NULL, 'Delegation · Overview', 'Work sits with the right people and you are not the dumping ground. That lets you lead rather than firefight. Strong spot. Now think forward: with the team owning their lanes, where could you focus your judgement to lift everyone''s game?', 41, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-office-trapped', 'summary', 'delegation', 'office', 'solo', 'trapped', NULL, 'Delegation · Overview', 'Every small thing waits on someone else''s say-so, and you are stuck holding work you cannot move. Nothing is clearly yours to decide. That is powerlessness dressed up as process, and it wastes your day. This is a business-level fix. Flagging where you are constantly blocked shows exactly where to loosen the reins.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-office-overloaded', 'summary', 'delegation', 'office', 'solo', 'overloaded', NULL, 'Delegation · Overview', 'You spend a lot of your day waiting on approvals or picking up slack that is not really yours. It dominates and pulls you off your own work. Some you can pre-empt, but the real issue is unclear ownership. Naming where the hand-offs stall most is the most useful thing you can do.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-office-stretched', 'summary', 'delegation', 'office', 'solo', 'stretched', NULL, 'Delegation · Overview', 'You keep your work moving, but you are often waiting on a decision or covering a gap. Slip and it backs up. You are coping. That waiting is a cost the business should see. Pointing out which approvals or hand-offs slow you most helps them fix the flow.', 48, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-office-driver', 'summary', 'delegation', 'office', 'solo', 'driver', NULL, 'Delegation · Overview', 'You own your work and can move it without constantly waiting on others. That is a good place to be. The value you add now is insight: you can see where responsibilities are clear and where they still tangle, which helps the business keep work flowing to the right people.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-field-trapped', 'summary', 'delegation', 'field', 'solo', 'trapped', NULL, 'Delegation · Overview', 'You cannot make a move without ringing base, and every decision waits on someone at a desk. Out on-site that leaves you stuck and idle. It is a design flaw, not your failing. The business needs to push real authority to the field, so you can act on the spot instead of standing around waiting.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-field-overloaded', 'summary', 'delegation', 'field', 'solo', 'overloaded', NULL, 'Delegation · Overview', 'Too much of your day is spent waiting on the office to approve or decide before you can get on. It dominates and drags out every job. The fix is not yours to make. It is the business trusting the field with clear authority, so you are not held up by a call that should not be needed.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-field-stretched', 'summary', 'delegation', 'field', 'solo', 'stretched', NULL, 'Delegation · Overview', 'You keep jobs moving, but you are often held up waiting on a decision from base. Busy days make it worse. You are coping, just. That waiting is time the business is losing. Flagging which approvals slow you down most on-site is the most valuable thing you can point to.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-solo-field-driver', 'summary', 'delegation', 'field', 'solo', 'driver', NULL, 'Delegation · Overview', 'You have the authority to make the calls you need on-site, and you are not held up by base. For field work that is genuinely good. The value now is insight: you know which decisions are best made on the ground, which helps the business keep pushing the right calls to the right place.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-boss-trapped', 'summary', 'delegation', 'boss', 'small', 'trapped', NULL, 'Delegation · Overview', 'With a team in place, work still funnelling back to you is a serious problem. You are the bottleneck every decision waits on, and your people cannot grow while you hold everything. This is a governance rebuild: define clear ownership and real authority, so the team runs the business rather than running to you.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-boss-overloaded', 'summary', 'delegation', 'boss', 'small', 'overloaded', NULL, 'Delegation · Overview', 'You have delegated, but the important calls and the loose ends keep bouncing back. It dominates your week and stops your team stepping up fully. The strategic move is to make ownership explicit and trust it, so your people carry their lanes and you stop being the default catch-all.', 49, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-boss-stretched', 'summary', 'delegation', 'boss', 'small', 'stretched', NULL, 'Delegation · Overview', 'Your team owns real work, but you are still the safety net when things slip or get complex. Cover is thin. You are managing well, on fine margins. Firming up accountability and cross-cover would take the fragility out and let you lead instead of backstop.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-boss-driver', 'summary', 'delegation', 'boss', 'small', 'driver', NULL, 'Delegation · Overview', 'Work sits with the right people, and you hold only what truly needs you. Your team owns their remit. That is a strong platform for growth. The question now is strategic: with your time freed, where do you steer the business next, and who do you develop to carry more?', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-lead-trapped', 'summary', 'delegation', 'lead', 'small', 'trapped', NULL, 'Delegation · Overview', 'Your team is set up so everything routes through you, and you have become the bottleneck. You cannot lead while you are the clearing house for every task and decision. This needs the business to redesign ownership, so work is distributed properly and your people are trusted to own it.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-lead-overloaded', 'summary', 'delegation', 'lead', 'small', 'overloaded', NULL, 'Delegation · Overview', 'Work that should sit with your team lands on you, or bounces around for want of a clear owner. It dominates your time and keeps your specialists from doing what they are good at. The fix is clearer governance: define who owns what, so your people specialise instead of shuffling admin.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-lead-stretched', 'summary', 'delegation', 'lead', 'small', 'stretched', NULL, 'Delegation · Overview', 'Your team owns their work, but you still catch a lot that falls between roles. One absence and it lands back on you. You are coping well. Tightening accountability and cover would give you and the team real slack instead of constant gap-filling.', 43, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-lead-driver', 'summary', 'delegation', 'lead', 'small', 'driver', NULL, 'Delegation · Overview', 'Work flows to the right people and your specialists get to specialise. You are leading, not backfilling. Strong position. Now look ahead: with clear ownership in place, how do you stretch the team and free even more of your time for the work that moves the needle?', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-office-trapped', 'summary', 'delegation', 'office', 'small', 'trapped', NULL, 'Delegation · Overview', 'You and your colleagues are stuck waiting on decisions and holding work you cannot move, while low-value tasks pile onto the wrong people. Nothing flows. That is a governance failure, not yours to fix. The business needs to clarify ownership and authority. Showing where work gets stuck helps them see it.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-office-overloaded', 'summary', 'delegation', 'office', 'small', 'overloaded', NULL, 'Delegation · Overview', 'A big part of your team''s day goes on waiting for approvals or absorbing work that belongs elsewhere. It dominates and keeps you from your real job. This is the business''s to fix through clearer ownership. Flagging where the bottlenecks and misassigned work concentrate points them to the right change.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-office-stretched', 'summary', 'delegation', 'office', 'small', 'stretched', NULL, 'Delegation · Overview', 'Your team keeps work moving, but there is a lot of waiting on sign-off and covering gaps. Busy weeks strain it. You are coping. That friction is a cost the business should see. Naming which approvals and hand-offs slow the team most helps them smooth the flow.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-office-driver', 'summary', 'delegation', 'office', 'small', 'driver', NULL, 'Delegation · Overview', 'Your team owns its work and moves it without constant waiting. Good place to be. The value you add now is visibility: you can see where responsibilities are clean and where they still snag, which is exactly what the business needs to keep work with the right people.', 48, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-field-trapped', 'summary', 'delegation', 'field', 'small', 'trapped', NULL, 'Delegation · Overview', 'Your crew cannot act without ringing base for every decision, and jobs stall while the wrong people hold authority. On-site that is dead time and frustration. It is a design problem the business owns. Pushing real authority to the field would unblock the crew. Flagging where they are stuck waiting shows where to start.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-field-overloaded', 'summary', 'delegation', 'field', 'small', 'overloaded', NULL, 'Delegation · Overview', 'The crew spends too much of the day waiting on the office to approve or decide. It dominates jobs and wastes skilled hands. The fix is the business trusting the field with clear authority, so work is not held up by calls that should not be needed. Naming the worst hold-ups points the way.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-field-stretched', 'summary', 'delegation', 'field', 'small', 'stretched', NULL, 'Delegation · Overview', 'Your crew keeps jobs moving, but they are often held up waiting on base. Busy days make it bite. They are coping, just. That waiting is time the business is losing. Flagging which decisions should be made on the ground is the most valuable input the crew can give.', 49, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-small-field-driver', 'summary', 'delegation', 'field', 'small', 'driver', NULL, 'Delegation · Overview', 'Your crew has the authority to make on-site calls and is not held up by base. For a field team that is genuinely strong. The value now is insight: your crew knows which decisions belong on the ground, which helps the business keep pushing the right authority to the right place as it grows.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-boss-trapped', 'summary', 'delegation', 'boss', 'medium', 'trapped', NULL, 'Delegation · Overview', 'At your scale, work still converging on you signals a broken operating model. Decisions bottleneck at the top while capable people wait, and the organisation cannot move at its size. This is structural: you need a governance and delegation redesign, so authority sits where the work is and the business runs without funnelling through you.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-boss-overloaded', 'summary', 'delegation', 'boss', 'medium', 'overloaded', NULL, 'Delegation · Overview', 'Your organisation delegates on paper, but too much still escalates to you and your senior team. It dominates leadership''s time and slows everything below. The strategic priority is clear decision rights and trusted ownership, so escalation is the exception, not the default, and leaders lead.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-boss-stretched', 'summary', 'delegation', 'boss', 'medium', 'stretched', NULL, 'Delegation · Overview', 'Work is distributed, but leadership still absorbs too many exceptions and gaps. It holds, at the cost of your senior people''s focus. Tightening decision rights and building proper cover would remove the fragility and free leadership for genuinely strategic work.', 40, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-boss-driver', 'summary', 'delegation', 'boss', 'medium', 'driver', NULL, 'Delegation · Overview', 'Authority sits where the work is, and your organisation runs without escalating everything upward. Leadership leads. That is a strong, scalable operating model. The question now is strategic: workforce planning, where to grow, and how to use freed leadership capacity to drive the next stage.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-lead-trapped', 'summary', 'delegation', 'lead', 'medium', 'trapped', NULL, 'Delegation · Overview', 'Your department funnels everything through you, and you have become a structural bottleneck. Skilled people wait while you clear the queue. You cannot manage at this scale as the single point everything passes through. The organisation needs to redistribute ownership and authority, so your team can move without you.', 49, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-lead-overloaded', 'summary', 'delegation', 'lead', 'medium', 'overloaded', NULL, 'Delegation · Overview', 'Work that belongs with your specialists lands on you or escalates for want of clear ownership. It dominates your time and keeps expensive expertise doing low-value shuffling. The fix is organisational governance: define decision rights so your people do the high-skill work only they can do.', 46, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-lead-stretched', 'summary', 'delegation', 'lead', 'medium', 'stretched', NULL, 'Delegation · Overview', 'Your team owns real responsibility, but you still catch a steady stream of exceptions and cross-role gaps. Volume strains it. You are managing well on a fragile base. Firming up accountability and cover across the department would give your people and you genuine headroom.', 44, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-lead-driver', 'summary', 'delegation', 'lead', 'medium', 'driver', NULL, 'Delegation · Overview', 'Work sits with the right specialists and your people operate at the top of their skill. You lead rather than backfill. Strong position at your scale. Now the opportunity is strategic: workforce planning and stretch, using your freed time to build the department''s next capability.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-office-trapped', 'summary', 'delegation', 'office', 'medium', 'trapped', NULL, 'Delegation · Overview', 'Across your function, people wait on approvals and hold work they cannot move, while tasks land on the wrong roles. Nothing flows and the errors mount. This is a structural governance failure the organisation owns. The most useful thing your team can do is map where work stalls and who is really doing what.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-office-overloaded', 'summary', 'delegation', 'office', 'medium', 'overloaded', NULL, 'Delegation · Overview', 'Your team loses significant time to approval queues and misassigned work. It dominates the function and keeps skilled people off their real jobs. This is the organisation''s to fix through clear decision rights. Flagging where the bottlenecks and duplication concentrate shows leadership where to act.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-office-stretched', 'summary', 'delegation', 'office', 'medium', 'stretched', NULL, 'Delegation · Overview', 'Your team keeps work moving, but constant waiting on sign-off and gap-covering leaves thin margins. Peak periods strain it. You are coping at a cost. That friction is something the organisation should see. Naming which approvals and hand-offs slow the function most helps target the fix.', 46, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-office-driver', 'summary', 'delegation', 'office', 'medium', 'driver', NULL, 'Delegation · Overview', 'Your team owns its work and moves it cleanly without constant escalation. Good position at your scale. The value you add now is visibility: your team can see where responsibilities are clear and where they still tangle, which is exactly what the organisation needs to keep work flowing to the right people.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-field-trapped', 'summary', 'delegation', 'field', 'medium', 'trapped', NULL, 'Delegation · Overview', 'Your field workforce cannot act without back-office sign-off on everything, and jobs stall at scale while authority sits in the wrong place. That is a major source of dead time across the workforce. It is a structural design fault the organisation owns. Pushing real authority to the field would unblock it. Map where crews are stuck.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-field-overloaded', 'summary', 'delegation', 'field', 'medium', 'overloaded', NULL, 'Delegation · Overview', 'Field crews spend heavily on waiting for back-office approvals and decisions. Across a workforce your size that is a serious drain and a lot of idle skilled time. The organisation should trust the field with clear authority, so work is not held up by avoidable calls. Flagging the worst hold-ups points the fix.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-field-stretched', 'summary', 'delegation', 'field', 'medium', 'stretched', NULL, 'Delegation · Overview', 'Your field workforce keeps jobs moving, but they are regularly held up waiting on base. Volume and poor connectivity make it bite. They are coping at a cost. That waiting scales into real lost time. Flagging which decisions belong on the ground is the most valuable input the workforce can give.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-delegation-medium-field-driver', 'summary', 'delegation', 'field', 'medium', 'driver', NULL, 'Delegation · Overview', 'Your field workforce holds the authority to make on-site calls and is not bottlenecked by the back office. At your scale that is a genuine operational strength. The value now is intelligence: crews know which decisions belong in the field, which helps the organisation keep decision rights in the right place as it scales.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-boss-solo', 'question', 'delegation', 'boss', 'solo', NULL, 'q4', 'Delegation · Q4', 'You do the low-value admin yourself because, right now, it genuinely is faster than explaining it. That logic is true today and a trap tomorrow. Every hour on repetitive tasks is an hour your business needs from you elsewhere. The goal is to make those tasks explainable and repeatable, so they can leave your desk, to a person or to automation.', 61, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-boss-small', 'question', 'delegation', 'boss', 'small', NULL, 'q4', 'Delegation · Q4', 'You still pick up repetitive admin because handing it over feels slower than doing it. With a team, that instinct is quietly costing you. It keeps you in the weeds and keeps them from stepping up. The strategic move is to invest the time once to document and delegate, so the task never lands on the owner again.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-boss-medium', 'question', 'delegation', 'boss', 'medium', NULL, 'q4', 'Delegation · Q4', 'Even at your scale you find yourself doing tasks far below your role because it feels faster than delegating. That is a signal your processes are not clear enough to hand over confidently. The fix is not your willpower. It is building the systems and clarity that make delegation reliable, so leadership time goes to leadership work.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-lead-solo', 'question', 'delegation', 'lead', 'solo', NULL, 'q4', 'Delegation · Q4', 'In a small team, work stalls the moment the one person who knows it is off, because it all lives in their head. You feel that fragility keenly. The answer is not heroics. It is capturing how things are done, so no single absence stops the business. Even light documentation turns a risk into resilience.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-lead-small', 'question', 'delegation', 'lead', 'small', NULL, 'q4', 'Delegation · Q4', 'Processes stall when the one person who holds the knowledge is on holiday, and you are left scrambling to cover. That single point of failure is a governance risk, not bad luck. The business should own capturing and sharing that knowledge, so work continues whoever is out. Flagging which roles carry hidden, undocumented knowledge is a strong start.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-lead-medium', 'question', 'delegation', 'lead', 'medium', NULL, 'q4', 'Delegation · Q4', 'Across your department, processes still hinge on individuals whose knowledge lives only in their heads. At your scale that is a serious continuity risk that surfaces every holiday and every resignation. The organisation must make knowledge a shared asset, not a personal one. Redesigning around documented process removes the fragility and frees your people.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-office-solo', 'question', 'delegation', 'office', 'solo', NULL, 'q4', 'Delegation · Q4', 'You often pause your own work waiting for a manager to approve something small. In a tiny team that wait feels personal and constant. It is stop-start time you cannot get back. The fix is agreeing which small decisions you can just make. Flagging where you are needlessly held up shows where trust could be loosened.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-office-small', 'question', 'delegation', 'office', 'small', NULL, 'q4', 'Delegation · Q4', 'A real slice of your week goes on waiting for sign-off on things that barely need it. It fragments your day and stalls your work. This is a governance issue the business should address by widening what you can decide yourself. Naming which approvals slow you most, and matter least, points to easy wins.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-office-medium', 'question', 'delegation', 'office', 'medium', NULL, 'q4', 'Delegation · Q4', 'You lose meaningful time each week paused, waiting on approvals for low-risk, routine things. Across your function that stop-start pattern is a structural drag built on old mistrust. The organisation should redesign approval thresholds so routine work flows. Flagging the approvals that add delay but no real control shows where to start.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-field-solo', 'question', 'delegation', 'field', 'solo', NULL, 'q4', 'Delegation · Q4', 'You stand around on-site waiting for the office to approve a quote or confirm a call. That idle time is money and momentum lost. Much of it comes from base not trusting the field to decide. Agreeing what you can approve on the spot would keep you moving. Flag where the waiting hurts most.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-field-small', 'question', 'delegation', 'field', 'small', NULL, 'q4', 'Delegation · Q4', 'Your crew loses time waiting on the office to approve quotes or confirm decisions before work can continue. That idle time adds up across jobs. The fix is the business granting the field clear limits to decide within, so momentum is not lost to avoidable calls. Naming the most common hold-ups points the way.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q4-field-medium', 'question', 'delegation', 'field', 'medium', NULL, 'q4', 'Delegation · Q4', 'Across your field workforce, waiting on back-office approval for quotes and decisions is a significant, recurring source of dead time. At your scale it compounds into serious lost capacity. The organisation should set clear field authority within defined limits, so crews keep moving. Flagging the approvals that cause the most standing around targets the fix.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-boss-solo', 'question', 'delegation', 'boss', 'solo', NULL, 'q5', 'Delegation · Q5', 'Setting up a new client means the same details keyed into several places, by you, every time. It is slow, and it is exactly when you want to be making a great first impression. The goal is one smooth intake that sets everything up at once, so onboarding takes minutes and you start every relationship on the front foot.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-boss-small', 'question', 'delegation', 'boss', 'small', NULL, 'q5', 'Delegation · Q5', 'Onboarding a new client or project still takes a manual march across disconnected processes. As you win more work, that setup cost scales badly and eats your team. The strategic move is to design onboarding as one clean flow, so growth does not mean proportionally more admin every single time.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-boss-medium', 'question', 'delegation', 'boss', 'medium', NULL, 'q5', 'Delegation · Q5', 'Standing up a new client, project or order takes your organisation a slow, manual trip across many systems. At your scale that setup drag delays revenue and frustrates customers from day one. This is a process-redesign opportunity: one orchestrated onboarding, so scale does not multiply the admin behind every new win.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-lead-solo', 'question', 'delegation', 'lead', 'solo', NULL, 'q5', 'Delegation · Q5', 'When you hit a ceiling, the instinct is to find another pair of hands, even in a small team. Often the real problem is the process, not the headcount. Adding people to a broken flow just spreads the load around. The stronger move is to fix the process first, so you grow on efficiency, not just bodies.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-lead-small', 'question', 'delegation', 'lead', 'small', NULL, 'q5', 'Delegation · Q5', 'When growth stalls, the default is often to hire more admin rather than fix the process causing the strain. That adds cost without removing the root problem. The strategic question is whether the work should exist at all. Redesigning the broken process usually beats hiring around it, and it scales far better.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-lead-medium', 'question', 'delegation', 'lead', 'medium', NULL, 'q5', 'Delegation · Q5', 'At your scale, hitting a bottleneck and reaching for more headcount is an expensive habit. It masks broken processes with bodies and inflates your cost base permanently. The organisation should treat the process as the fix first: redesign before you rehire. Strategic workforce planning means adding people for growth, not to patch friction.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-office-solo', 'question', 'delegation', 'office', 'solo', NULL, 'q5', 'Delegation · Q5', 'Work gets handed to you missing the context you need, so you go back and chase the details. In a small team that is quick but constant, and it interrupts both of you. Agreeing what a proper hand-off includes would cut the back-and-forth. Flagging what is usually missing is a simple, useful start.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-office-small', 'question', 'delegation', 'office', 'small', NULL, 'q5', 'Delegation · Q5', 'Tasks land on you without the instructions or context to act, so you spend time chasing the person who delegated. That rework is friction the business builds by not standardising hand-offs. This is not yours to fix alone. Naming what is routinely missing shows where a simple hand-off standard would save everyone time.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-office-medium', 'question', 'delegation', 'office', 'medium', NULL, 'q5', 'Delegation · Q5', 'Across your function, incomplete hand-offs mean constant chasing for missing context before work can start. At your scale that back-and-forth is a serious, hidden drain. The organisation should standardise what a complete hand-off carries, so work arrives ready to action. Your team can flag where the gaps are most costly.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-field-solo', 'question', 'delegation', 'field', 'solo', NULL, 'q5', 'Delegation · Q5', 'You arrive on-site missing key information, so you ring the office or ask the customer to go over it again. It is an awkward, avoidable start that eats time. The fix is making sure the job details reach you before you go. Flagging what is usually missing on arrival shows what the hand-off should always include.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-field-small', 'question', 'delegation', 'field', 'small', NULL, 'q5', 'Delegation · Q5', 'Your crew often reaches site without the full picture, forcing calls to base or repeat questions to the customer. That undermines confidence and wastes time on every affected job. The business should own getting complete job information to the field first time. Naming what is most often missing points to the fix.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q5-field-medium', 'question', 'delegation', 'field', 'medium', NULL, 'q5', 'Delegation · Q5', 'Across your field workforce, arriving on-site without complete information is a recurring failure that triggers calls, delays and repeat questions to customers. At your scale it dents both efficiency and reputation. The organisation must ensure the field is fully briefed before arrival. Flagging the information gaps that recur most targets the redesign.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-boss-trapped', 'summary', 'prioritisation', 'boss', 'solo', 'trapped', NULL, 'Prioritisation · Overview', 'Your day is entirely reactive. Whoever shouts loudest sets your agenda, and the work that would actually grow the business never gets a look in. You are busy from dawn to dusk with nothing to show for it strategically. This is the clearest sign you need to take back control of where your attention goes, before the business can move forward.', 61, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-boss-overloaded', 'summary', 'prioritisation', 'boss', 'solo', 'overloaded', NULL, 'Prioritisation · Overview', 'Interruptions run your day. Emails, messages and small fires pull you off anything important, and the real work gets pushed into the evening. You are staying on top of it, barely, at the cost of your own time. The move is to protect your best hours deliberately, so what matters gets your attention, not just what is loud.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-boss-stretched', 'summary', 'prioritisation', 'boss', 'solo', 'stretched', NULL, 'Prioritisation · Overview', 'You manage to focus on what matters, but only by fighting for it, and the interruptions never really stop. Let your guard down and the day runs away. You are coping. That constant defending of your time is the tax. A little structure around your attention would turn the fight into a rhythm.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-boss-driver', 'summary', 'prioritisation', 'boss', 'solo', 'driver', NULL, 'Prioritisation · Overview', 'You decide where your attention goes, and the important work actually happens. Interruptions do not own your day. For a solo operator that is genuinely hard-won. Now the question is strategic: with your focus protected, what is the one thing you could point it at that would change the trajectory of the business?', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-lead-trapped', 'summary', 'prioritisation', 'lead', 'solo', 'trapped', NULL, 'Prioritisation · Overview', 'Your day is spent reacting, mopping up other people''s urgencies and covering for broken processes, with no space for the work you are meant to lead. You have lost control of your own priorities. This is not a discipline problem. It is a signal that what is important to the business is not being protected, and that needs fixing above you.', 61, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-lead-overloaded', 'summary', 'prioritisation', 'lead', 'solo', 'overloaded', NULL, 'Prioritisation · Overview', 'Constant interruptions and other people''s priorities dominate your week, pushing your real work later and later. You are staying afloat but never getting ahead. The opening is for the business to protect what matters and cut the noise, so you lead the important work instead of forever reacting to the urgent.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-lead-stretched', 'summary', 'prioritisation', 'lead', 'solo', 'stretched', NULL, 'Prioritisation · Overview', 'You keep the important work moving, but only by constantly pushing back the interruptions. Busy spells tip the balance. You are managing well, on effort alone. Some agreed protection of focus time would let you lead consistently rather than defend your calendar every day.', 44, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-lead-driver', 'summary', 'prioritisation', 'lead', 'solo', 'driver', NULL, 'Prioritisation · Overview', 'You and your team focus on what genuinely matters, and the day is not hijacked by noise. That control lets you lead properly. Strong position. Now look forward: with attention protected, where do you point the team''s focus to make the biggest difference?', 43, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-office-trapped', 'summary', 'prioritisation', 'office', 'solo', 'trapped', NULL, 'Prioritisation · Overview', 'Your day is a stream of interruptions and other people''s urgencies, and your own work never gets a clear run. You are reacting from start to finish. That is exhausting and it is not of your making. The business needs to protect focus and fix what keeps derailing you. Flagging what interrupts you most is a valuable start.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-office-overloaded', 'summary', 'prioritisation', 'office', 'solo', 'overloaded', NULL, 'Prioritisation · Overview', 'Chat messages, emails and quick questions dominate your day, and your real work gets squeezed into the gaps. You are keeping up, but only just. Some of this you can manage locally, but the culture of constant interruption is the business''s to address. Naming the biggest disruptions points to where focus could be protected.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-office-stretched', 'summary', 'prioritisation', 'office', 'solo', 'stretched', NULL, 'Prioritisation · Overview', 'You get your work done, but you are forever context-switching between it and everyone else''s asks. Busy days make focus hard to hold. You are coping. That fragmentation is a hidden cost. Pointing out what breaks your concentration most helps the business protect deep work for everyone.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-office-driver', 'summary', 'prioritisation', 'office', 'solo', 'driver', NULL, 'Prioritisation · Overview', 'You can focus on your work without being pulled in ten directions. That is a good place to be. The value you add now is insight: you can see what protects focus and what erodes it, which is exactly what the business needs to help the whole team work on the right things.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-field-trapped', 'summary', 'prioritisation', 'field', 'solo', 'trapped', NULL, 'Prioritisation · Overview', 'Your day on-site is constantly ripped up by calls, texts and changes from base, so you never get a clean run at the actual job. You are reacting to the office all day. That is not your doing. The business needs to shield the field from constant interruption. Flagging what disrupts you most on-site shows where to start.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-field-overloaded', 'summary', 'prioritisation', 'field', 'solo', 'overloaded', NULL, 'Prioritisation · Overview', 'The phone never stops while you are trying to work, and last-minute changes keep derailing your day. You are getting the jobs done, but the noise makes it harder than it should be. The fix is the business managing how and when the field is contacted, so you can focus on the job in front of you.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-prioritisation-solo-field-stretched', 'summary', 'prioritisation', 'field', 'solo', 'stretched', NULL, 'Prioritisation · Overview', 'You keep the jobs on track, but the steady stream of calls and changes from base makes it a constant juggle. Busy days tip it. You are coping, just. That interruption is time and focus the business is costing you. Naming the disruptions that bite most helps them protect your working day.', 52, NULL);
