INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q6-boss-solo', 'question', 'prioritisation', 'boss', 'solo', NULL, 'q6', 'Prioritisation · Q6', 'Every ping pulls you off the work that actually matters, and getting back into it takes far longer than the interruption itself. As a one-person show, you are the only line of defence for your own focus. The goal is to design boundaries around your attention, so client noise does not quietly decide what your day becomes.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q6-boss-small', 'question', 'prioritisation', 'boss', 'small', NULL, 'q6', 'Prioritisation · Q6', 'Client emails and notifications fragment your day, and the deep work that grows the business keeps losing to the interruptions. With a team, some of that noise should not reach you at all. The move is to build a buffer, so routine pings are handled without you and your focus is protected for what only you can do.', 58, NULL);
