INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q6-field-solo', 'question', 'prioritisation', 'field', 'solo', NULL, 'q6', 'Prioritisation · Q6', 'Your phone lights up with calls and texts from the office while you are trying to work, and every one breaks your flow. On-site that is a genuine safety and quality risk, not just an annoyance. Agreeing when the office should and should not contact you would help. Flag the interruptions that disrupt you most.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q6-field-small', 'question', 'prioritisation', 'field', 'small', NULL, 'q6', 'Prioritisation · Q6', 'The office contacts the crew constantly while they are mid-job, breaking concentration and slowing the work. That steady stream of calls and texts is a habit the business can change. Setting clear rules for when and how the field is contacted would protect the work. Naming the worst interruptions points the way.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q6-field-medium', 'question', 'prioritisation', 'field', 'medium', NULL, 'q6', 'Prioritisation · Q6', 'Across your field workforce, constant back-office contact mid-job fragments focus and dents quality and safety. At your scale that is a coordination problem, not a crew one. The organisation should manage field communication deliberately, batching non-urgent contact. Flagging which interruptions cost the most helps target the fix.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-boss-solo', 'question', 'prioritisation', 'boss', 'solo', NULL, 'q7', 'Prioritisation · Q7', 'You log back on after 8pm because the day never gave you room for the actual work. That evening shift feels like dedication, but it is really the admin winning. It is not sustainable and it is not why you started the business. The goal is to fix the day so the important work fits inside it, and your evenings are yours again.', 63, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-boss-small', 'question', 'prioritisation', 'boss', 'small', NULL, 'q7', 'Prioritisation · Q7', 'You are back online in the evenings because the day is swallowed by everything else. With a team, that is a sign too much still depends on you and too little runs on its own. Protecting your day by offloading and automating the routine would mean the important work happens in hours, not after them.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-boss-medium', 'question', 'prioritisation', 'boss', 'medium', NULL, 'q7', 'Prioritisation · Q7', 'Regularly working late to catch up, even at your level, signals an organisation that fills your day with the wrong things. It is a warning about capacity and delegation, not a badge of commitment. The fix is structural: redesign so leadership work fits the day, protecting your focus and modelling a sustainable pace for the whole organisation.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-lead-solo', 'question', 'prioritisation', 'lead', 'solo', NULL, 'q7', 'Prioritisation · Q7', 'You see your key people logging on late or at weekends just to keep up. In a small team, that is your best talent quietly heading for burnout. It is a signal the workload or the process is off, not that they are slow. Protecting them starts with fixing what forces the extra hours. Flag where it happens most.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-lead-small', 'question', 'prioritisation', 'lead', 'small', NULL, 'q7', 'Prioritisation · Q7', 'Your key team members regularly work late or over the weekend just to stay afloat. That is a burnout risk and a retention risk hiding in plain sight. It usually points to broken process or unrealistic load, not individual failings. The business should fix the causes. Naming who is consistently over-stretched shows where to look.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-lead-medium', 'question', 'prioritisation', 'lead', 'medium', NULL, 'q7', 'Prioritisation · Q7', 'Across your department, valued people routinely work evenings and weekends to keep up. At your scale that is a systemic capacity and process problem, and a serious risk to wellbeing and retention. The organisation must treat chronic overwork as a design fault to fix, not a resource to rely on. Flag where it concentrates.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-office-solo', 'question', 'prioritisation', 'office', 'solo', NULL, 'q7', 'Prioritisation · Q7', 'You or your colleagues log back on in the evening to get the actual work done, because the day gets eaten by everything else. In a small team that creep feels normal. It is not sustainable. The business should see it as a signal to fix. Flagging what pushes the real work into your own time is a useful start.', 60, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-office-small', 'question', 'prioritisation', 'office', 'small', NULL, 'q7', 'Prioritisation · Q7', 'You and colleagues regularly catch up on evenings or weekends because the working day does not allow for the real work. That quiet expectation is a cost the business often does not see. It is a process and workload issue, not a personal one. Naming what forces the after-hours catch-up helps the business address it.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-office-medium', 'question', 'prioritisation', 'office', 'medium', NULL, 'q7', 'Prioritisation · Q7', 'Across your function, people routinely work outside hours just to keep up, and it has become normalised. At your scale that is a structural workload and process failure, with real burnout risk. The organisation should treat it as a signal to redesign, not a resource to lean on. Your team can flag what drives the overrun.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-field-solo', 'question', 'prioritisation', 'field', 'solo', NULL, 'q7', 'Prioritisation · Q7', 'Your day gets torn up by last-minute changes and poor routing from base, so you are forever chasing a schedule that keeps shifting. That churn wastes fuel, time and patience. Better planning from the office would steady your day. Flagging where the routing and changes hurt most shows what needs tightening.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-field-small', 'question', 'prioritisation', 'field', 'small', NULL, 'q7', 'Prioritisation · Q7', 'The crew''s schedules are regularly ripped up by last-minute changes and poor routing from the office. That churn wastes travel time and disrupts every affected job. It is a planning problem the business owns, not a field failing. Better scheduling and routing would steady the days. Naming the worst patterns points to the fix.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q7-field-medium', 'question', 'prioritisation', 'field', 'medium', NULL, 'q7', 'Prioritisation · Q7', 'Across your field workforce, last-minute changes and poor routing constantly disrupt schedules, wasting travel, time and morale at scale. That is a structural planning and coordination failure the organisation owns. Smarter scheduling and routing would recover serious capacity. Flagging where the disruption concentrates helps target the redesign.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-boss-trapped', 'summary', 'tech', 'boss', 'solo', 'trapped', NULL, 'Tech · Overview', 'Your tech is working against you, not for you. Tools that do not fit, do not talk, or that you never had time to learn properly. As a solo operator, every gap lands on you. This is not about buying more software. It is about getting the right, simple foundations in place, so technology finally saves you time instead of costing it.', 62, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-boss-overloaded', 'summary', 'tech', 'boss', 'solo', 'overloaded', NULL, 'Tech · Overview', 'You have tools, but they add as much admin as they remove, and you have not had the time to get comfortable with them. It dominates more than it should. The move is not another app. It is stripping back to what genuinely helps and learning to use it well, so tech becomes an enabler, not another job.', 58, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-boss-stretched', 'summary', 'tech', 'boss', 'solo', 'stretched', NULL, 'Tech · Overview', 'Your tech mostly does the job, but you rely on workarounds and you know you are not using it to its full potential. It holds, with effort. You are close. A little investment in the right setup and in your own confidence with it would turn "making do" into genuinely working smarter.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-boss-driver', 'summary', 'tech', 'boss', 'solo', 'driver', NULL, 'Tech · Overview', 'Your tech supports you well and you are comfortable getting the most from it. That is a strong base for a solo operator. Now the opportunity opens up: with solid foundations and clean information, you are in a great position to let smart automation and AI take the routine off your plate entirely.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-lead-trapped', 'summary', 'tech', 'lead', 'solo', 'trapped', NULL, 'Tech · Overview', 'The tech your team relies on is broken or missing, and people are not confident using what you do have. You spend your time working around it. That is a foundation problem, not a training afterthought. The business needs to fix the tools and build real confidence, so tech supports the team instead of holding it back.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-lead-overloaded', 'summary', 'tech', 'lead', 'solo', 'overloaded', NULL, 'Tech · Overview', 'Your tools half-help and half-hinder, and your team is not fully fluent with them, so they lean on you. It dominates more than it should. The fix is not more software. It is the right tools plus genuine, hands-on support to use them well, so the team gains confidence and the tech starts pulling its weight.', 56, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-lead-stretched', 'summary', 'tech', 'lead', 'solo', 'stretched', NULL, 'Tech · Overview', 'Your team gets by with the tech, but through workarounds and without real fluency, so it takes constant effort. It holds, just. Investing in the right setup and in your people''s confidence with it would turn making-do into genuinely working smarter, and take the pressure off you.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-lead-driver', 'summary', 'tech', 'lead', 'solo', 'driver', NULL, 'Tech · Overview', 'Your team has the right tools and the confidence to use them well. Tech enables rather than obstructs. Strong position. Now look ahead: with solid foundations and a capable team, you are well placed to bring in smart automation that frees people for higher-value work.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-office-trapped', 'summary', 'tech', 'office', 'solo', 'trapped', NULL, 'Tech · Overview', 'The tech you work with is broken, ill-fitting or something you were never properly shown how to use, so you fight it all day. That is not your failing, it is a business one. Naming what does not work and where you lack confidence is genuinely useful. The fix, the right tools and real training, sits with the business.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-office-overloaded', 'summary', 'tech', 'office', 'solo', 'overloaded', NULL, 'Tech · Overview', 'Your tools add nearly as much work as they save, and you have not had the support to get fully comfortable with them. It weighs on your day. Some you can learn around, but the real fix, better tools and proper training, is the business''s to provide. Flagging what hinders you most points the way.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-office-stretched', 'summary', 'tech', 'office', 'solo', 'stretched', NULL, 'Tech · Overview', 'You make the tech work, but through workarounds and self-taught habits rather than real fluency. It takes effort to stay on top of it. You are coping. Better setup and proper training would lift you from getting by to genuinely confident. Naming where you feel least sure is a helpful start.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-office-driver', 'summary', 'tech', 'office', 'solo', 'driver', NULL, 'Tech · Overview', 'You are comfortable with your tools and they support your work well. Good place to be. The value you add now is insight and, often, quiet leadership: you can help colleagues who are less confident, and you can see where the tech could do more, which is exactly what the business needs to keep improving.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-field-trapped', 'summary', 'tech', 'field', 'solo', 'trapped', NULL, 'Tech · Overview', 'The tech meant to help you on-site fails you, wrong for the job, unreliable, or never properly explained, so you fall back on manual workarounds constantly. That is a business failing, not yours. The fix is field-fit tools and real support to use them. Flagging what breaks down most on-site is where to start.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-field-overloaded', 'summary', 'tech', 'field', 'solo', 'overloaded', NULL, 'Tech · Overview', 'Your field tools half-work and often add hassle, and you have not been properly shown how to get the best from them. It drags on your day. The fix is not more gadgets. It is the right, rugged, simple tools plus proper support, which the business owns. Naming what hinders you most on-site helps.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-field-stretched', 'summary', 'tech', 'field', 'solo', 'stretched', NULL, 'Tech · Overview', 'You make the on-site tech work, but with workarounds and without full confidence, so it takes effort. It holds, just. The right field-fit setup and proper training would turn making-do into genuinely working smarter. Flagging where the tech lets you down most on the ground points to the fix.', 49, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-solo-field-driver', 'summary', 'tech', 'field', 'solo', 'driver', NULL, 'Tech · Overview', 'Your on-site tech works for you and you are confident using it. For field work that is genuinely good. The value now is insight: you know what works on the ground and what does not, which is exactly what the business needs when choosing and rolling out tools for the field.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-small-boss-trapped', 'summary', 'tech', 'boss', 'small', 'trapped', NULL, 'Tech · Overview', 'Your business runs on tech that is broken, mismatched or barely understood, and your people are not confident with it. That drags on everything and lands back on you. This is a foundations problem. Before any talk of AI, the business needs the right tools and a team confident to use them, so technology starts enabling growth, not blocking it.', 60, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-small-boss-overloaded', 'summary', 'tech', 'boss', 'small', 'overloaded', NULL, 'Tech · Overview', 'You have accumulated tools that add as much admin as they remove, and your team is not fully fluent with them. That sprawl and skills gap quietly caps the business. The strategic move is to rationalise to what genuinely helps and invest in your people''s confidence, so tech becomes an enabler rather than a tax.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-small-boss-stretched', 'summary', 'tech', 'boss', 'small', 'stretched', NULL, 'Tech · Overview', 'Your tech mostly works, but on workarounds and without your team using it to its potential. It holds, with effort. You are close. Tidying the toolset and building real fluency across the team would turn making-do into genuine leverage, and set you up for smarter automation later.', 47, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-small-boss-driver', 'summary', 'tech', 'boss', 'small', 'driver', NULL, 'Tech · Overview', 'Your business has the right tools and a team confident using them. Tech enables the work rather than fighting it. Strong platform. The opportunity now is strategic: with solid foundations and clean data, you are well placed to bring in automation and AI that scale output without scaling headcount.', 49, NULL);
