INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-small-lead-overloaded', 'summary', 'tech', 'lead', 'small', 'overloaded', NULL, 'Tech · Overview', 'Tool sprawl and shaky fluency mean your team spends real effort fighting the tech rather than using it. It dominates more than it should. The fix is the business rationalising the toolset and investing properly in training, so your people gain confidence and the tech starts pulling its weight.', 49, NULL);
