INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-lead-driver', 'summary', 'tech', 'lead', 'medium', 'driver', NULL, 'Tech · Overview', 'Your team has the right, integrated tools and the fluency to use them well. Tech enables rather than obstructs. Strong position at your scale. Now the opportunity is strategic: with a capable team and clean foundations, you are well placed to lead the adoption of automation that elevates your people''s work.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-office-trapped', 'summary', 'tech', 'office', 'medium', 'trapped', NULL, 'Tech · Overview', 'Across your function, people battle fragmented, broken tools they were never properly trained on, and the workarounds compound. It is draining and structural. The organisation owns the fix: the right integrated tools and real training. The most useful thing your team can do is map what does not work and where confidence is lowest.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-office-overloaded', 'summary', 'tech', 'office', 'medium', 'overloaded', NULL, 'Tech · Overview', 'Tool sprawl and patchy fluency mean your team loses real time fighting technology rather than using it. Across a function your size that is a serious drain. The organisation should rationalise the stack and invest in training. Flagging what hinders the team most, and where skills gaps concentrate, shows where to act.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-office-stretched', 'summary', 'tech', 'office', 'medium', 'stretched', NULL, 'Tech · Overview', 'Your team makes the tech work, but through workarounds and uneven fluency, leaving thin margins. It holds until change hits. Better-integrated tools and proper training would lift the function from coping to confident. Naming where the team feels least capable helps the organisation target its investment.', 46, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-office-driver', 'summary', 'tech', 'office', 'medium', 'driver', NULL, 'Tech · Overview', 'Your team is capable with well-integrated tools that support the work. Good position at your scale. The value you add now is visibility and peer capability: your team can see where tech could do more and can help others level up, which is exactly what the organisation needs to keep adoption strong.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-field-trapped', 'summary', 'tech', 'field', 'medium', 'trapped', NULL, 'Tech · Overview', 'Across your field workforce, tech fails constantly, wrong for the conditions, unreliable connectivity, or never properly rolled out, so crews default to manual workarounds at scale. That is a major structural cost the organisation owns. Field-fit tools and real support are the fix. Flag what breaks most on-site to target it.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-field-overloaded', 'summary', 'tech', 'field', 'medium', 'overloaded', NULL, 'Tech · Overview', 'Field tools that half-work and uneven familiarity mean your workforce spends serious effort fighting technology. At your scale that drags heavily. The organisation should provide the right, rugged, simple tools plus proper support and training. Flagging what hinders crews most on-site shows where to invest.', 45, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-field-stretched', 'summary', 'tech', 'field', 'medium', 'stretched', NULL, 'Tech · Overview', 'Your field workforce makes the on-site tech work, but with workarounds and partial confidence, leaving thin margins and hidden fragility. It holds, at a cost. The right field-fit setup and proper training would turn making-do into working smarter across the workforce. Flag where the tech lets crews down most.', 49, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('sum-tech-medium-field-driver', 'summary', 'tech', 'field', 'medium', 'driver', NULL, 'Tech · Overview', 'Your field workforce runs on tech that works in the field, with crews confident using it. At your scale that is a genuine strength. The value now is intelligence: your crews know what works on the ground and what does not, which is exactly what the organisation needs when selecting and rolling out field technology at scale.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-boss-solo', 'question', 'tech', 'boss', 'solo', NULL, 'q8', 'Tech · Q8', 'You buy a tool to save time, and it quietly adds more, because it does not talk to anything else you use. Now you are the connection between them. That is the easy-fix trap: each point solution solves one thing and fragments the rest. The smarter path is choosing tools that fit together, so they save time instead of multiplying it.', 61, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-boss-small', 'question', 'tech', 'boss', 'small', NULL, 'q8', 'Tech · Q8', 'Every new tool the business adopts seems to create fresh admin because it does not sync with the rest, and your team ends up bridging the gaps by hand. That is point-solution sprawl in miniature, and it compounds as you grow. The strategic move is to stop buying in isolation and design a connected toolset that actually works as one.', 60, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-boss-medium', 'question', 'tech', 'boss', 'medium', NULL, 'q8', 'Tech · Q8', 'Across your organisation, tools bought to save time keep adding admin because they do not integrate, and staff become the manual glue. At your scale that sprawl carries a heavy complexity tax. The fix is deliberate: rationalise and integrate the stack, so new tools connect by design rather than creating another silo to bridge.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-lead-solo', 'question', 'tech', 'lead', 'solo', NULL, 'q8', 'Tech · Q8', 'Even in a small team, different tools get picked up piecemeal, and now nothing quite talks to anything. You feel it in the manual joins. The answer is not another tool. It is a deliberate, connected setup. Flagging where the disconnects cost your team most shows where joining things up would help.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-lead-small', 'question', 'tech', 'lead', 'small', NULL, 'q8', 'Tech · Q8', 'Departments and individuals buy their own software, and you are left with a bloated set of tools where nothing connects, so your people become the bridges. That sprawl is a governance gap the business should close. Consolidating and integrating deliberately would cut the manual joins. Naming the worst disconnects points to where to start.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-lead-medium', 'question', 'tech', 'lead', 'medium', NULL, 'q8', 'Tech · Q8', 'Across your department, uncoordinated software buying has left a bloated stack where nothing talks to each other, and your people manually bridge it. At your scale that is a serious complexity tax and a barrier to automation. The organisation needs governed procurement and real integration, so the stack works as one system, not many silos.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-office-solo', 'question', 'tech', 'office', 'solo', NULL, 'q8', 'Tech · Q8', 'A new tool arrives meant to help, and it just adds another place to enter things by hand. In a small setup that lands straight on you. It is not you doing it wrong, it is the tool not connecting. Flagging when new tools add work instead of removing it helps the business choose better next time.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-office-small', 'question', 'tech', 'office', 'small', NULL, 'q8', 'Tech · Q8', 'When the business brings in a new tool, it often adds a layer of admin rather than talking to what you already use, so you re-enter the same data again. That is a real cost the business rarely sees. This is not yours to fix. Flagging which tools add work instead of saving it points to what needs joining up.', 60, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-office-medium', 'question', 'tech', 'office', 'medium', NULL, 'q8', 'Tech · Q8', 'New tools regularly land on your team and simply add another silo to feed by hand, rather than integrating with your existing systems. At your scale that duplication is a structural drain. The organisation should require integration before rollout. Your team can flag which tools create the most duplicate work, guiding better decisions.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-field-solo', 'question', 'tech', 'field', 'solo', NULL, 'q8', 'Tech · Q8', 'Field software that freezes, or makes you type the same thing twice, costs you real time on-site. It is meant to help and instead it holds you up. That is a tool problem, not a you problem. Flagging where the software fails or doubles your work shows what needs fixing or replacing.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-field-small', 'question', 'tech', 'field', 'small', NULL, 'q8', 'Tech · Q8', 'Your crew loses time to field software that freezes or forces the same information to be entered more than once. That is friction the tool is causing, and it adds up across jobs. The business should fix or replace what is not working on-site. Naming the worst offenders helps them act.', 51, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q8-field-medium', 'question', 'tech', 'field', 'medium', NULL, 'q8', 'Tech · Q8', 'Across your field workforce, unreliable software that freezes or forces duplicate entry costs serious time at scale. That is a structural tooling failure, not a crew one. The organisation should fix or replace field software that fails in real conditions. Flagging where it breaks and duplicates most targets the investment.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-boss-solo', 'question', 'tech', 'boss', 'solo', NULL, 'q9', 'Tech · Q9', 'You have dabbled with AI for the odd task, but most of your actual work is still done by hand. That gap is normal, and it is opportunity. The point is not to use AI for its own sake. It is to spot the repetitive work eating your week and let smart tools genuinely take it off you, so your hours go to what matters.', 65, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-boss-small', 'question', 'tech', 'boss', 'small', NULL, 'q9', 'Tech · Q9', 'You use AI in small ways, but the bulk of the work is still manual, and the real time-savers have not landed. That is the common gap between dabbling and genuine change. The opportunity is to move from isolated speed-ups to automating whole chunks of routine work, so the business gains real capacity, not just faster typing.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-boss-medium', 'question', 'tech', 'boss', 'medium', NULL, 'q9', 'Tech · Q9', 'Your organisation uses AI at the edges, but most core work is still manual, and the promised gains have not materialised. That is the process-translation gap: individual speed-ups that never became systemic change. The opportunity is to redesign whole workflows around automation, so the business captures real capacity rather than scattered minutes.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-lead-solo', 'question', 'tech', 'lead', 'solo', NULL, 'q9', 'Tech · Q9', 'You have tried AI tools, but they end up used for small speed-ups rather than real change. In a small team that is understandable, and it is a missed opportunity. The value comes from rethinking the work itself, not bolting AI onto it. Flagging the repetitive work that eats your team''s time shows where real automation would pay off.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-lead-small', 'question', 'tech', 'lead', 'small', NULL, 'q9', 'Tech · Q9', 'You invest in AI tools, then watch them used only for minor speed-ups, never real automation. That is the surface-level trap, and it wastes the investment. The shift is to redesign the process around what the tools can genuinely do. Naming the routine work ripe for automation is where the real returns start.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-lead-medium', 'question', 'tech', 'lead', 'medium', NULL, 'q9', 'Tech · Q9', 'Your organisation buys enterprise AI and copilots, only to see them used for basic task speed-ups instead of genuine automation. At your scale that is a costly under-return and a strategic miss. The fix is to stop layering AI onto legacy processes and redesign the work around it, capturing the systemic gains the tools were bought for.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-office-solo', 'question', 'tech', 'office', 'solo', NULL, 'q9', 'Tech · Q9', 'Despite all the AI talk, most of your repetitive daily work is still completely manual. That is not you falling behind, it is the tools not yet pointed at the right tasks. Flagging which repetitive jobs eat your day most is genuinely useful. It shows the business exactly where automation would give you time back.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-office-small', 'question', 'tech', 'office', 'small', NULL, 'q9', 'Tech · Q9', 'A lot of your daily repetitive work is still fully manual, despite the talk of AI everywhere. The gap between the hype and your actual day is real. This is the business''s to close by targeting the right tasks. Naming your most repetitive, manual jobs points to where automation would help you most.', 53, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-office-medium', 'question', 'tech', 'office', 'medium', NULL, 'q9', 'Tech · Q9', 'Across your team, much of the repetitive daily work remains completely manual, even as the organisation talks about AI. That gap between talk and reality is a real drain at your scale. The organisation should target automation at the genuinely repetitive work. Your team can flag which tasks are most manual and ripe for it.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-field-solo', 'question', 'tech', 'field', 'solo', NULL, 'q9', 'Tech · Q9', 'Poor signal on-site makes your tech fail, forcing you back to manual workarounds and later re-entry. That is a real, practical block that no amount of clever software fixes on its own. The answer is tech that works offline and syncs later. Flagging where signal fails you most shows what the field setup actually needs.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-field-small', 'question', 'tech', 'field', 'small', NULL, 'q9', 'Tech · Q9', 'Your crew regularly hits signal blackspots that make the tech fail, forcing manual workarounds and double handling later. That is a practical reality the business must design for, not blame the crew for. Offline-capable tools that sync when back in range are the fix. Naming where signal fails most helps target it.', 52, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q9-field-medium', 'question', 'tech', 'field', 'medium', NULL, 'q9', 'Tech · Q9', 'Across your field workforce, poor connectivity routinely causes tech to fail, forcing manual workarounds at scale. That is a structural design failure, not a crew one. The organisation must deploy offline-first field tools that sync automatically, so connectivity gaps stop costing time. Flagging where signal fails most guides the rollout.', 50, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-boss-solo', 'question', 'tech', 'boss', 'solo', NULL, 'q10', 'Tech · Q10', 'If you handed your business to an AI agent tomorrow, it would stumble fast, because your data and files are scattered and messy. That is not a failing, it is where almost everyone starts. The point is that clean, organised information is the real foundation. Get that right and the clever tools become genuinely possible. It is the groundwork that pays off.', 62, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-boss-small', 'question', 'tech', 'boss', 'small', NULL, 'q10', 'Tech · Q10', 'Try to run the business through an AI agent today and it would struggle, because the underlying data is messy and disconnected. That readiness gap is exactly why so many AI efforts stall. The strategic move is to treat clean, organised data as the foundation, so when you do bring in automation, it works instead of hallucinating.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-boss-medium', 'question', 'tech', 'boss', 'medium', NULL, 'q10', 'Tech · Q10', 'If you pointed an AI agent at your operations today, it would fail quickly on messy, fragmented data. Data readiness is the number one reason automation projects collapse, and at your scale the stakes are high. The strategic priority is a clean, governed data foundation first, so any agentic AI you deploy actually delivers rather than amplifying the mess.', 59, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-lead-solo', 'question', 'tech', 'lead', 'solo', NULL, 'q10', 'Tech · Q10', 'The worry that AI might make a wrong call or mishandle data holds you back from letting it run anything unsupervised. In a small team that caution is sensible, not a weakness. The answer is starting where the risk is low and keeping a human in the loop. Naming where you would and would not trust automation is a healthy first step.', 62, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-lead-small', 'question', 'tech', 'lead', 'small', NULL, 'q10', 'Tech · Q10', 'Fear of AI making an unapproved decision or leaking data stops you deploying anything autonomous, and rightly, that caution matters. The answer is not to avoid it, but to deploy with clear guardrails and human oversight where it counts. Defining where automation is safe and where a human must sign off turns fear into a workable plan.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-lead-medium', 'question', 'tech', 'lead', 'medium', NULL, 'q10', 'Tech · Q10', 'At your scale, the fear of AI making an unauthorised financial call or leaking data is a serious, legitimate barrier to autonomous workflows. That caution is appropriate, not an obstacle to dismiss. The answer is governance: clear human-in-the-loop controls, audit trails and defined limits, so you can adopt automation safely rather than avoid it entirely.', 55, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-field-solo', 'question', 'tech', 'field', 'solo', NULL, 'q10', 'Tech · Q10', 'You often feel stuck with software clearly built for someone at a desk, not someone on the move. That mismatch is a real, daily frustration, and it is the tool''s fault, not yours. Field work needs field-fit tech. Flagging where the software fails you on the move shows exactly what a better setup would need to handle.', 57, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-field-small', 'question', 'tech', 'field', 'small', NULL, 'q10', 'Tech · Q10', 'Your crew is regularly stuck using software designed for a desk, not a job site. That mismatch slows every affected task and frustrates good people. The business should choose tools built for the field, not force desk software onto it. Naming where the current software fails on the move points to what to fix.', 54, NULL);
INSERT INTO report_nodes (id, node_type, section, role, company_size, tier, question_id, label, body, word_count, updated_at) VALUES ('q10-field-medium', 'question', 'tech', 'field', 'medium', NULL, 'q10', 'Tech · Q10', 'Across your field workforce, desk-designed software forced onto mobile work is a constant, scaling frustration. That mismatch costs time and morale, and it is a procurement failure, not a crew one. The organisation should select genuinely field-fit, mobile-first tools. Flagging where current software fails on the move guides better decisions.', 50, NULL);
